import { BehaviorSubject, Observable, scan, Subject } from "rxjs";

interface Counter {
  n: number;
}
type Action = { type: "inc" } | { type: "dec" } | { type: "reset" };

function reduce(s: Counter, a: Action): Counter {
  switch (a.type) {
    case "inc": return { n: s.n + 1 };
    case "dec": return { n: s.n - 1 };
    case "reset": return { n: 0 };
  }
}

const actions$ = new Subject<Action>();
const state$ = new BehaviorSubject<Counter>({ n: 0 });
actions$.pipe(scan(reduce, { n: 0 })).subscribe(state$);

export const store$: Observable<Counter> = state$.asObservable();
export function dispatch(a: Action): void { actions$.next(a); }
