  return defer<Observable<Result>>(() => throwError(() => new Error("503")));
}

export const withBackoff$: Observable<Result> = call$().pipe(
  retry({
    count: 4,
    delay: (_err: unknown, n: number): Observable<number> => timer(2 ** n * 100),
  })
);
