import { fromEvent, Observable, switchMap, takeUntil, map } from "rxjs";

interface Rect { x: number; y: number; w: number; h: number; }

export function selection$(el: HTMLElement): Observable<Rect> {
  const down$ = fromEvent<PointerEvent>(el, "pointerdown");
  const move$ = fromEvent<PointerEvent>(window, "pointermove");
  const up$ = fromEvent<PointerEvent>(window, "pointerup");
  return down$.pipe(
    switchMap((d: PointerEvent) => move$.pipe(
      map((m: PointerEvent): Rect => ({
        x: Math.min(d.clientX, m.clientX),
        y: Math.min(d.clientY, m.clientY),
        w: Math.abs(m.clientX - d.clientX),
        h: Math.abs(m.clientY - d.clientY),
      })),
      takeUntil(up$)
    ))
  );
}
