import { Observable, retry, timer, throwError } from "rxjs";

interface RetryCfg {
  count: number;
  isRetryable: (e: unknown) => boolean;
  base: number;
}

export function withBackoff<T>(source$: Observable<T>, cfg: RetryCfg): Observable<T> {
  return source$.pipe(
    retry({
      count: cfg.count,
      delay: (err: unknown, n: number): Observable<number> =>
        cfg.isRetryable(err) ? timer(2 ** n * cfg.base) : throwError(() => err),
    })
  );
}
